var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"크리스마스 당일\\n사건 발생 <color=#ffd34c>1시간 전</color>","JPN":"クリスマス当日\\n事件発生<color=#ffd34c>1時間前</color>","ENG":"[[","TWN":"聖誕節當天\\n事件發生 <color=#ffd34c>1小時前</color>","SCN":"圣诞节当天\\n事件发生 <color=#ffd34c>1小时前</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 기적심의회 제5본당","JPN":"<color=#ffd34c>聖皇庁</color>奇跡審議会第5本堂","ENG":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council's 5th Parish","TWN":"<color=#ffd34c>聖皇廳</color> 奇蹟議會第五主堂","SCN":"<color=#ffd34c>圣廷</color> 奇迹议会第五本堂","DEU":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council's 5th Parish","FRA":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council's 5th Parish"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"후우, 어디보자…….","JPN":"ふう、さてと……","ENG":"Phew, what's left...?","TWN":"呼嗚，讓我看看……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"크리스마스 트리도 세웠고, 벽난로에 불도 피웠어. 장작도 충분하고.","JPN":"クリスマスツリーも飾り付けて、暖炉に火もつけた。薪も十分あるね。","ENG":"The Christmas tree is up, the fireplace is lit, and it has enough firewood.","TWN":"聖誕樹立好了，壁爐裡的火也點燃了，柴火也足夠了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"성탄제에 오실 손님 분들께 나누어 드릴 선물도 준비했고, 그리고 또…….","JPN":"聖誕祭に参加するお客さんに差し上げるプレゼントも用意したし、それから……","ENG":"All the gifts for our guests are here, and...","TWN":"我還為來參加宴會的客人們準備了禮物，還有……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"아, 깜빡했네! 이런 날 롤링페이퍼를 잊으면 안 되겠지?","JPN":"あ、そう！　こんな日に寄せ書きは外せないよね。","ENG":"Oh, right! I can't believe I forgot about the roll sheet.","TWN":"啊，我差點忘了！這種日子怎麼能忘了寫祝福的話呢？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"오늘은 성탄절이기도 하지만, 루퍼 자매님의 사제 서품을 축하하는 날이기도 하니까…….","JPN":"今日は聖誕祭だけど、シスター・シンディの司祭叙階を祝う日でもあるから……","ENG":"Today is Christmas, but it's also a day to celebrate Sister Looper's ordination...","TWN":"今天不僅是聖誕節，也是慶祝洛珀姊妹晉升祭司的日子……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"후훗, 손님 분들께 축하 메시지를 남겨달라고 하면, 분명 자매님도 기뻐할 거야.","JPN":"ふふっ、お客さんにお祝いのメッセージを残してもらったら、きっとシスター・シンディも喜ぶはずよ。","ENG":"Haha, I'm sure Sister Looper will be pleased to receive congratulatory messages from all the guests.","TWN":"呵呵，要是能請客人們留下祝福的話，她一定會很高興的。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"흐음! 좋아, 데코레이션은 이 정도면 된 것 같네.","JPN":"ふう！　よし、デコレーションはこれくらいでいいよね。","ENG":"Hmm! Okay, that should be all the decorations.","TWN":"嗯！就這樣，裝飾到這個程度就可以了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"음? 창밖에서 무언가…….","JPN":"うん？　窓の外で何か……","ENG":"Mm? Is there something outside...?","TWN":"嗯？窗外有什麼……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"눈이 내리잖아…? 잠깐 사이에 이렇게 쌓이다니……!","JPN":"雪が降ってる……？　いつの間にこんなに積もっちゃって……！","ENG":"It's snowing...? And it's already piled up so much...!","TWN":"下雪了……？這麼短的時間就積這麼厚了……！"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"잠깐, 눈이라면……?","JPN":"待って、雪なら……？","ENG":"Wait, snow...?","TWN":"等一下，下雪的話……？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이건, 함박눈이 새하얗게 떨어지는 화이트 크리스마스의 밤…….","JPN":"これは、真っ白な綿雪の降るホワイトクリスマスの夜……","ENG":"It is... a special, sweet dessert that you would share with your friends and family on a white Christmas night,","TWN":"這是一個大雪紛飛的白色聖誕夜……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"벽난로를 쬐며 다 함께 나누어 먹었을 때, 가장 특별하고 달콤한 디저트라고 할 수 있죠.","JPN":"暖炉に当たりながらみんなで食べれば、何よりも特別で甘いデザートとなるでしょう。","ENG":"...gathered around the fireplace as soft snowflakes fall outside.","TWN":"圍坐在壁爐旁一起分享時，可以說是最特別、最甜美的點心。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇구나! 화이트 크리스마스!","JPN":"そうか！　ホワイトクリスマス！","ENG":"Oh! A white Christmas!","TWN":"原來如此！白色聖誕節！"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"후훗, 주님께서도 오늘 밤의 성탄제를 축복해 주시는 게 틀림없어……!","JPN":"ふふっ、神も今夜の聖誕祭を祝福してくださっているのよ……！","ENG":"Haha, the Lord must be blessing tonight's Christmas party...!","TWN":"嘿嘿，主也一定會祝福今晚的聖誕節……！"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"자비로우신 주님…….","JPN":"慈しみ深い神よ……","ENG":"Oh, merciful Lord...","TWN":"慈悲的主……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"부디, 오늘 밤 성탄제에 초대받은 모든 이들이 소중한 추억을 쌓을 수 있도록 도와주세요.","JPN":"どうか、今夜の聖誕祭に招待されたみなさんが、大切な思い出を作れるようお見守りください。","ENG":"Please help everyone invited to the party create cherished memories.","TWN":"請幫助今晚受邀參加聖誕節的所有人留下珍貴的回憶。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"부디, 오늘 밤 성탄제를 시작으로 두 자매님의 사이가 좋아질 수 있도록 도와주세요.","JPN":"どうか、今夜の聖誕祭をきっかけにあの2人が仲良くなれるよう導き下さい。","ENG":"Please help the two Sisters become closer on this wonderful night.","TWN":"希望從今晚的聖誕聚會開始，兩位姊妹的關係能夠親密起來。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"마지막으로 오늘 밤 성탄제를 위해, 만드는 <color=#ffd34c>성야의 쇼콜라 무스 케이크</color>가 실패하지 않도록 도와주세요.","JPN":"最後に、今夜の聖誕祭のために作る<color=#ffd34c>聖夜のムースショコラ</color>が失敗しませんよう力をお貸しください。","ENG":"Lastly, please give me the strength to bake the perfect <color=#ffd34c>holy night chocolate mousse cake</color> for tonight's Christmas party.","TWN":"最後，為了今晚的宴會，請幫忙確保<color=#ffd34c>平安夜巧克力慕斯蛋糕</color>能夠成功製作出來。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"주님의 이름으로 기도드립니다. 아멘.","JPN":"神の名のもとにお祈り申し上げます。アーメン。","ENG":"In the name of our Lord. I pray. Amen.","TWN":"奉主的名祈禱，阿門。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"자, 그러면 손님들께서 오시기 전에 서둘러서 끝내볼까……!","JPN":"さて、お客さんが来る前に急いで終わらせましょうか……！","ENG":"Now, let's finish up before our guests start coming in...!","TWN":"那麼，在客人們來之前趕緊完成吧……！"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};